using Microsoft.Extensions.Logging.Abstractions;

namespace VoxelForge.Core.Benchmarking;

/// <summary>
/// Deterministic reference scenes for renderer performance benchmarking.
/// Each scene is generated by a stateless factory method that produces a
/// <see cref="VoxelModel"/> with a predictable voxel count, bounds, and
/// palette usage.
/// <para>
/// These scenes are intended for comparing FNA/Myra and Electron/Three.js
/// renderer mesh generation, snapshot/serialization, and scene construction
/// latency. They are <em>not</em> normal test fixtures — they live in Core
/// so both evaluation and integration tests can reference them without
/// depending on rendering framework types.
/// </para>
/// </summary>
public static class RendererBenchmarkScenes
{
    /// <summary>
    /// Small scene: a 10x10x10 hollow cube (~488 visible voxels on surface).
    /// Well below 1k voxels — fast for any mesher.
    /// </summary>
    public static VoxelModel SmallHollowCube()
    {
        var model = new VoxelModel(NullLogger<VoxelModel>.Instance);
        model.GridHint = 16;
        SetupBasicPalette(model);

        // 10x10x10 hollow box: outer shell only (wall thickness = 1)
        // Surface voxels: 10*10*2 (top/bottom) + 10*8*2 (sides) + 8*8*2 (front/back)
        // = 200 + 160 + 128 = 488
        FillHollowBox(model, 0, 0, 0, 9, 9, 9, 1);
        return model;
    }

    /// <summary>
    /// Medium scene: a 22x22x22 hollow cube with internal pillars (~2,996 voxels).
    /// Approximately 3k voxels — moderate mesh cost.
    /// </summary>
    public static VoxelModel MediumHollowWithPillars()
    {
        var model = new VoxelModel(NullLogger<VoxelModel>.Instance);
        model.GridHint = 32;
        SetupBasicPalette(model);

        int size = 22;
        FillHollowBox(model, 0, 0, 0, size - 1, size - 1, size - 1, 1);

        // 4 internal 2x2 pillars from y=1 to y=20 at (5,5), (5,15), (15,5), (15,15)
        int[] pillarPositions = [5, 15];
        foreach (int px in pillarPositions)
        foreach (int pz in pillarPositions)
            FillBox(model, px, 1, pz, px + 1, size - 2, pz + 1, 2);

        // Cross-bracing at mid-height
        int midY = size / 2;
        for (int x = 7; x <= 14; x++)
        {
            model.SetVoxel(new Point3(x, midY, 7), 2);
            model.SetVoxel(new Point3(x, midY, 14), 2);
        }
        for (int z = 7; z <= 14; z++)
        {
            model.SetVoxel(new Point3(7, midY, z), 2);
            model.SetVoxel(new Point3(14, midY, z), 2);
        }

        return model;
    }

    /// <summary>
    /// Large scene: a 48x48x48 room with a grid of internal walls and pillars (~24k voxels).
    /// Designed to stress the greedy mesher with many separate faces and occlusions.
    /// </summary>
    public static VoxelModel LargeGridRoom()
    {
        var model = new VoxelModel(NullLogger<VoxelModel>.Instance);
        model.GridHint = 64;
        SetupBasicPalette(model);

        int size = 48;
        FillHollowBox(model, 0, 0, 0, size - 1, size - 1, size - 1, 1);

        // Internal walls every 12 units with door openings
        for (int wallPos = 12; wallPos < size - 6; wallPos += 12)
        {
            // X-aligned wall at fixed Z (spans X, full height Y, thin in Z)
            FillWallWithDoorway(model, 0, 0, wallPos, size - 1, size - 1, wallPos, 2, 3);
            // Z-aligned wall at fixed X (thin in X, full height Y, spans Z)
            FillWallWithDoorway(model, wallPos, 0, 0, wallPos, size - 1, size - 1, 2, 3);
        }

        // 2x2 pillars at wall intersections
        int[] pillarPositions = [12, 24, 36];
        foreach (int px in pillarPositions)
        foreach (int pz in pillarPositions)
            FillBox(model, px, 1, pz, px + 1, size - 3, pz + 1, 4);

        return model;
    }

    /// <summary>
    /// Extra-large scene: a 64x64x64 densely filled region with checkerboard pattern (~131k voxels).
    /// Opt-in only — too expensive for default CI runs.
    /// </summary>
    public static VoxelModel ExtraLargeCheckerboard()
    {
        var model = new VoxelModel(NullLogger<VoxelModel>.Instance);
        model.GridHint = 64;
        SetupBasicPalette(model);

        int size = 64;
        for (int x = 0; x < size; x += 2)
        for (int y = 0; y < size; y += 2)
        for (int z = 0; z < size; z += 2)
        {
            bool fill = ((x / 2) + (y / 2) + (z / 2)) % 2 == 0;
            if (fill)
            {
                byte idx = (byte)(((x / 2) % 4) + 1);
                FillBox(model, x, y, z, x + 1, y + 1, z + 1, idx);
            }
        }

        return model;
    }

    /// <summary>
    /// Return expected voxel count for each scene, for verification in tests.
    /// </summary>
    public static int ExpectedVoxelCount(SceneId scene)
    {
        return scene switch
        {
            SceneId.SmallHollowCube => 488,
            SceneId.MediumHollowWithPillars => 2996,
            SceneId.LargeGridRoom => 25892,
            SceneId.ExtraLargeCheckerboard => 131072,
            _ => 0,
        };
    }

    /// <summary>
    /// Build a scene by ID.
    /// </summary>
    public static VoxelModel Build(SceneId scene)
    {
        return scene switch
        {
            SceneId.SmallHollowCube => SmallHollowCube(),
            SceneId.MediumHollowWithPillars => MediumHollowWithPillars(),
            SceneId.LargeGridRoom => LargeGridRoom(),
            SceneId.ExtraLargeCheckerboard => ExtraLargeCheckerboard(),
            _ => throw new ArgumentOutOfRangeException(nameof(scene), scene, null),
        };
    }

    /// <summary>
    /// Array of standard (non-extra-large) scene IDs for CI-friendly benchmark runs.
    /// </summary>
    public static SceneId[] DefaultScenes =>
    [
        SceneId.SmallHollowCube,
        SceneId.MediumHollowWithPillars,
        SceneId.LargeGridRoom,
    ];

    /// <summary>
    /// Array of all scene IDs, including extra-large (opt-in).
    /// </summary>
    public static SceneId[] AllScenes =>
    [
        SceneId.SmallHollowCube,
        SceneId.MediumHollowWithPillars,
        SceneId.LargeGridRoom,
        SceneId.ExtraLargeCheckerboard,
    ];

    // ── Private helpers ──

    private static void SetupBasicPalette(VoxelModel model)
    {
        model.Palette.Set(1, new MaterialDef
        {
            Name = "gray",
            Color = new RgbaColor(128, 128, 128, 255),
        });
        model.Palette.Set(2, new MaterialDef
        {
            Name = "blue",
            Color = new RgbaColor(64, 64, 200, 255),
        });
        model.Palette.Set(3, new MaterialDef
        {
            Name = "red",
            Color = new RgbaColor(200, 64, 64, 255),
        });
        model.Palette.Set(4, new MaterialDef
        {
            Name = "green",
            Color = new RgbaColor(64, 200, 64, 255),
        });
    }

    private static void FillBox(VoxelModel model, int x1, int y1, int z1, int x2, int y2, int z2, byte paletteIndex)
    {
        for (int x = x1; x <= x2; x++)
        for (int y = y1; y <= y2; y++)
        for (int z = z1; z <= z2; z++)
            model.SetVoxel(new Point3(x, y, z), paletteIndex);
    }

    private static void FillHollowBox(VoxelModel model, int x1, int y1, int z1, int x2, int y2, int z2, byte paletteIndex)
    {
        // Top and bottom faces
        for (int x = x1; x <= x2; x++)
        for (int z = z1; z <= z2; z++)
        {
            model.SetVoxel(new Point3(x, y1, z), paletteIndex);
            model.SetVoxel(new Point3(x, y2, z), paletteIndex);
        }

        // Front and back faces — skip y edges already filled
        for (int x = x1; x <= x2; x++)
        for (int y = y1 + 1; y <= y2 - 1; y++)
        {
            model.SetVoxel(new Point3(x, y, z1), paletteIndex);
            model.SetVoxel(new Point3(x, y, z2), paletteIndex);
        }

        // Left and right faces — skip already-filled edges
        for (int y = y1 + 1; y <= y2 - 1; y++)
        for (int z = z1 + 1; z <= z2 - 1; z++)
        {
            model.SetVoxel(new Point3(x1, y, z), paletteIndex);
            model.SetVoxel(new Point3(x2, y, z), paletteIndex);
        }
    }

    private static void FillWallWithDoorway(
        VoxelModel model,
        int x1, int y1, int z1,
        int x2, int y2, int z2,
        byte wallIndex, byte doorHighlightIndex)
    {
        // Fill the slab
        for (int x = x1; x <= x2; x++)
        for (int y = y1; y <= y2; y++)
        for (int z = z1; z <= z2; z++)
            model.SetVoxel(new Point3(x, y, z), wallIndex);

        bool spansX = (x2 - x1) > (z2 - z1);
        int doorWidth = 3;
        int doorHeight = 4;

        int cx = spansX ? (x1 + x2) / 2 : x1;
        int cz = spansX ? z1 : (z1 + z2) / 2;

        // Clear doorway
        int half = doorWidth / 2;
        for (int dy = 0; dy < doorHeight; dy++)
        for (int dx = -half; dx <= half; dx++)
        for (int dz = -half; dz <= half; dz++)
        {
            int px = spansX ? cx + dx : cx;
            int py = y1 + dy;
            int pz = spansX ? cz : cz + dz;
            model.RemoveVoxel(new Point3(px, py, pz));
        }

        // Door lintel highlight
        for (int d = -half - 1; d <= half + 1; d++)
        {
            if (spansX)
                model.SetVoxel(new Point3(cx + d, y1 + doorHeight, cz), doorHighlightIndex);
            else
                model.SetVoxel(new Point3(cx, y1 + doorHeight, cz + d), doorHighlightIndex);
        }
    }
}

/// <summary>
/// Identifiers for each benchmark scene.
/// </summary>
public enum SceneId
{
    SmallHollowCube,
    MediumHollowWithPillars,
    LargeGridRoom,
    ExtraLargeCheckerboard,
}
